const express = require('express');
const redis = require('redis');
const twilio = require('twilio');
const rateLimit = require('express-rate-limit');
const app = express();

app.use(express.json());

const redisClient = redis.createClient({
  host: process.env.REDIS_HOST || 'localhost',
  port: process.env.REDIS_PORT || 6379
});

const twilioClient = twilio(
  process.env.TWILIO_ACCOUNT_SID,
  process.env.TWILIO_AUTH_TOKEN
);

const MAX_ATTEMPTS = 10;
const CODE_EXPIRATION = 600; // 10 minutes
const CODE_LENGTH = 6;

// Rate limiting for code verification
const verifyLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5,
  message: 'Too many verification attempts, please try again later'
});

// Rate limiting for code generation
const generateLimiter = rateLimit({
  windowMs: 60 * 60 * 1000, // 1 hour
  max: 5,
  message: 'Too many code generation requests, please try again later'
});

// Generate 6-digit code
function generateCode() {
  return Math.floor(Math.random() * 900000) + 100000;
}

// Send SMS code
async function sendSMS(phoneNumber, code) {
  try {
    await twilioClient.messages.create({
      body: `Your verification code is: ${code}`,
      from: process.env.TWILIO_PHONE_NUMBER,
      to: phoneNumber
    });
  } catch (error) {
    console.error('SMS sending failed:', error);
    throw new Error('Failed to send verification code');
  }
}

// Store code in Redis
async function storeCode(userId, code) {
  const key = `mfa:${userId}`;
  const attemptsKey = `attempts:${userId}`;
  
  await redisClient.set(key, code, 'EX', CODE_EXPIRATION);
  await redisClient.incr(attemptsKey);
  await redisClient.expire(attemptsKey, CODE_EXPIRATION);
}

// Get stored code
async function getStoredCode(userId) {
  const key = `mfa:${userId}`;
  return await redisClient.get(key);
}

// Check if user is locked out
async function isLockedOut(userId) {
  const attemptsKey = `attempts:${userId}`;
  const attempts = await redisClient.get(attemptsKey);
  return attempts && parseInt(attempts) >= MAX_ATTEMPTS;
}

// Clear attempts
async function clearAttempts(userId) {
  const attemptsKey = `attempts:${userId}`;
  await redisClient.del(attemptsKey);
}

// Generate and send code
app.post('/mfa/generate', generateLimiter, async (req, res) => {
  try {
    const { userId, phoneNumber } = req.body;
    
    if (!userId || !phoneNumber) {
      return res.status(400).json({ error: 'Missing required fields' });
    }
    
    if (await isLockedOut(userId)) {
      return res.status(429).json({ error: 'Account locked due to too many attempts' });
    }
    
    const code = generateCode();
    await storeCode(userId, code);
    await sendSMS(phoneNumber, code);
    
    res.json({ message: 'Verification code sent' });
  } catch (error) {
    console.error('Code generation error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

// Verify code
app.post('/mfa/verify', verifyLimiter, async (req, res) => {
  try {
    const { userId, code } = req.body;
    
    if (!userId || !code) {
      return res.status(400).json({ error: 'Missing required fields' });
    }
    
    if (await isLockedOut(userId)) {
      return res.status(429).json({ error: 'Account locked due to too many attempts' });
    }
    
    const storedCode = await getStoredCode(userId);
    
    if (!storedCode) {
      return res.status(400).json({ error: 'No active verification code' });
    }
    
    if (storedCode !== code.toString()) {
      const attemptsKey = `attempts:${userId}`;
      const attempts = await redisClient.incr(attemptsKey);
      
      if (attempts >= MAX_ATTEMPTS) {
        return res.status(429).json({ error: 'Account locked due to too many attempts' });
      }
      
      return res.status(400).json({ error: 'Invalid verification code' });
    }
    
    await redisClient.del(`mfa:${userId}`);
    await clearAttempts(userId);
    
    res.json({ message: 'Verification successful' });
  } catch (error) {
    console.error('Verification error:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

module.exports = app;